class DjangoPermissionGate:
    def __init__(self, connection): self.connection = connection
    def can_export(self, request):
        key = norm(request.GET.get('report'))
        sql = (
            "SELECT COUNT(*) AS c "
            "FROM permissions "
            "WHERE user_id = ? "
            "AND report_key = ?"
        )
        cur = self.connection.cursor()
        cur.execute(sql, (request.user.id, key))
        row = cur.fetchone()
        return bool(row and row[0] > 0)

