fixed_code:
// Fix C: migrate complex raw SQL construction to Criteria API / query builder
CriteriaBuilder cb = entityManager.getCriteriaBuilder();
CriteriaQuery<User> cq = cb.createQuery(User.class);
Root<User> user = cq.from(User.class);
List<Predicate> predicates = new ArrayList<>();
for (Map.Entry<String,String> e : filters.entrySet()) {
    if (!ALLOWED_FILTERS.contains(e.getKey())) throw new IllegalArgumentException("Invalid filter");
    predicates.add(cb.equal(user.get(e.getKey()), e.getValue()));
}
cq.where(predicates.toArray(new Predicate[0]));
return entityManager.createQuery(cq).getResultList();

